firmware_template.source:
#include "threshold_alert.h"
#define MAX_ALERTS 16
static struct{float lo,hi;alert_cb cb;bool triggered;}_alerts[MAX_ALERTS];
static uint8_t _cnt=0;
void alert_setup(){_cnt=0;}
uint8_t alert_add(float lo,float hi,alert_cb cb){if(_cnt>=MAX_ALERTS)return 255;_alerts[_cnt]={lo,hi,cb,false};return _cnt++;}
void alert_check(uint8_t id,float v){if(id>=_cnt)return;if((v<_alerts[id].lo||v>_alerts[id].hi)&&!_alerts[id].triggered){_alerts[id].triggered=true;if(_alerts[id].cb)_alerts[id].cb(id,v);}else if(v>=_alerts[id].lo&&v<=_alerts[id].hi){_alerts[id].triggered=false;}}
